async function 江湖长梦(d) {
  var config, copy_name, data_dict, day, duration, enabled, end_date, ins_data, ins_id, material_id, material_name, material_quantity, max_copies, month, name, year;
  await d.get("cmd=jianghudream");
  ins_data = d.findall("id=(\\d+)\">(.*?)<");
  if (!pyTruthy(ins_data)) {
    d.log("无法获取副本id");
    return;
  }
  config = d.config("江湖长梦");
  max_copies = pyInt(d.config("江湖长梦.单次最大副本次数"));
  for (let [name, data_dict] of pyItems(config)) {
    if ((name === "单次最大副本次数")) {
      continue;
    }
    enabled = data_dict["enabled"];
    if (!pyTruthy(enabled)) {
      continue;
    }
    material_name = data_dict["material_name"];
    material_id = data_dict["material_id"];
    for (let [ins_id, copy_name] of ins_data) {
      if ((name !== copy_name)) {
        continue;
      }
      await d.get(`cmd=jianghudream&op=showCopyInfo&id=${ins_id}`);
      duration = d.find("副本时长：(\\d+)");
      if ((duration === null)) {
        d.log(`${name} -> 获取副本时长失败`);
        break;
      }
      if ((!contains(d.html, "常规副本"))) {
        year = d.find("-(\\d+)年");
        month = d.find("-\\d+年(\\d+)月");
        day = d.find("-\\d+年\\d+月(\\d+)日");
        if (((year === null) || (month === null) || (day === null))) {
          d.log(`${name} -> 获取结束日期失败`);
          return;
        }
        end_date = DateTime.get_offset_date(pyAdd(2000, pyInt(year)), pyInt(month), pyInt(day));
        if ((DateTime.current_date() > end_date)) {
          d.log(`${name} -> 不在开启时间内`);
          continue;
        }
      }
      material_quantity = await c_get_material_quantity(d, material_id);
      if ((material_quantity === 0)) {
        d.log(`${name} -> ${material_name}不足`);
        continue;
      }
      if ((material_quantity > max_copies)) {
        d.log(`${name} -> 本次最多开启${max_copies}次，剩余留待下次`);
        material_quantity = max_copies;
      }
      await __globals[name](d, name, ins_id, material_quantity, pyInt(duration));
    }
  }
}

