async function 年兽大作战(d) {
  var _id, choose_count, choose_ids, name, t;
  await d.get("cmd=newAct&subtype=170&op=0");
  if ((contains(d.html, "等级不够"))) {
    d.log("等级不够，还未开启年兽大作战哦！");
    return;
  }
  if (pyTruthy((choose_count = pyCount(d.html, "暂未选择")))) {
    choose_ids = [];
    for (let t of pyRange(5)) {
      await d.get(`cmd=newAct&subtype=170&op=4&type=${t}`);
      choose_ids = pyAdd(choose_ids, d.findall("id=(\\d+)\">选择"));
      if ((pyLen(choose_ids) >= choose_count)) {
        break;
      }
    }
    if ((pyLen(choose_ids) < choose_count)) {
      d.log("自选武技库数量不够补位");
      return;
    }
    for (let _id of pySlice(choose_ids, null, choose_count)) {
      await d.get(`cmd=newAct&subtype=170&op=7&id=${_id}`);
      name = d.find(`id=${_id}">(.*?)<`);
      d.log(`${name}：${d.find()}`);
    }
  }
  if ((contains(d.html, "剩余免费随机次数：1"))) {
    await d.get("cmd=newAct&subtype=170&op=6");
    d.log(d.find());
  }
  for (let _ of pyRange(3)) {
    await d.get("cmd=newAct&subtype=170&op=8");
    d.log(d.find());
    await sleep(0.2);
  }
}

